export const InboxController = ({
    children,
    fixedFontSize,
}: {
    children: React.ReactNode;
    fixedFontSize?: string;
}) => {
    const location = useLocation();
    const sendCommand = useSendCommand();

    useSetBaseFontSizeEffect(fixedFontSize);

    useEffect(() => {
        handleBrowserClass();
        (async () => {
            const { show } = await bridge();
            show?.();
        })();
    }, []);

    useEffect(() => {
        const { state } = window.history;
        const isHome = state && state.home;

        sendCommand(SHOW_BACK_BUTTON, !isHome);
    }, [location]);

    return Children.only(children);
};
import { useEffect } from "react";
import { handleFontSizeChange } from "./handle-set-font-size-change";
import { GameName, gameSettings } from "inbox-contentful";

export const useSetBaseFontSizeEffect = (fixedFontSize?: string) => {
    const referenceWidth =
        gameSettings[window.GAMENAME as GameName].referenceWidth;

    useEffect(() => {
        const handler = handleFontSizeChange(referenceWidth, fixedFontSize);

        setTimeout(handler, 0);

        window.addEventListener("resize", handler);

        const timeout = setInterval(() => {
            handler();
        }, 250);

        return () => {
            clearTimeout(timeout);
            window.removeEventListener("resize", handler);
        };
    }, []);
};
export const handleFontSizeChange =
    (referenceWidth: number, fixedFontSize?: string) => () => {
        if (fixedFontSize) {
            document.documentElement.style.fontSize = fixedFontSize;
            return;
        }
        const size = Math.round((16 / referenceWidth) * window.innerWidth);
        document.documentElement.style.fontSize = `${size}px`;
    };
export const handleBrowserClass = () => {
    const userAgent = navigator.userAgent;
    const browserPatterns = [
        { name: "chrome", regex: /Chrome\/(\d+)\./ },
        { name: "safari", regex: /Version\/(\d+)\.\d+.*Safari/ },
        { name: "safari", regex: /iPhone OS (\d+)_/ }, // Older versions of Safari
    ];

    let browser: string | null = null;
    let version: string | null = null;

    for (const { name, regex } of browserPatterns) {
        const match = userAgent.match(regex);
        if (match) {
            browser = name;
            version = match[1] ?? null;
            break;
        }
    }

    if (browser && version) {
        document.body.classList.add(`${browser}-${version}`);
    }
};
