export type GameParams = z.infer<typeof GameParams>;

export function parseGameParams<T>(
    input: unknown,
    parser: Parseable<T>,
): { output: T; validationError?: ZodError } {
    try {
        return { output: parser.parse(input) };
    } catch (ex) {
        if (ex instanceof ZodError) {
            const maintenance = Boolean(
                (input as Record<string, unknown>).maintenance,
            );
            return {
                output: {
                    ...(input as Record<string, unknown>),
                    maintenance,
                } as T,
                validationError: ex,
            };
        }

        throw ex;
    }
}
