export const getCustomAppId = (id: CustomApp, env?: string): AppId => {
  const possibleEnv = KnownContentfulEnvironment.safeParse(
    env ?? process.env.CONTENTFUL_ENVIRONMENT,
  );

  const knownEnv: KnownContentfulEnvironment = possibleEnv.success
    ? possibleEnv.data
    : "staging";

  const appId = EnvironmentSpecificAppIds[knownEnv][id];

  if (!appId) {
    throw new Error(`No app id found for ${id} in ${knownEnv}`);
  }

  return appId;
};

export const getPollBaseUrl = (): string => {
  const possibleEnv = KnownContentfulEnvironment.safeParse(
    process.env.CONTENTFUL_ENVIRONMENT,
  );

  const gameNameRes = GameName.safeParse(process.env.GAMENAME);

  if (!gameNameRes.success) {
    return "";
  }

  const gameName = gameNameRes.data;

  if (!possibleEnv.success) {
    return `https://${gameName}-api.inbox-dev.supercell.com/poll-api/poll/admin/`;
  }

  switch (possibleEnv.data) {
    case "master":
      return `https://${gameName}-api.inbox.supercell.com/poll-api/poll/admin/`;
    case "staging":
      return `https://${gameName}-api.inbox-staging.supercell.com/poll-api/poll/admin/`;
    case "dev":
      return `https://${gameName}-api.inbox-dev.supercell.com/poll-api/poll/admin/`;
  }
};

