function parseResponseData<T>(
  input: unknown,
  parser: Parseable<T>,
): { output: T; validationError?: ZodError } {
  try {
    return { output: parser.parse(input) };
  } catch (ex) {
    if (ex instanceof ZodError) {
      return { output: input as T, validationError: ex };
    }

    throw ex;
  }
}

export const parseBridgeFunctionResult = async <T>(
  bridgeFn: ((...args: unknown[]) => Promise<string>) | undefined,
  parser: Parseable<T>,
) => {
  const getParamsRes = await bridgeFn?.();

  const { output: gameParams, validationError } = parseResponseData<T>(
    JSON.parse(getParamsRes || '{ "data": {} }').data,
    parser,
  );

  return { gameParams, validationError };
};

