});

let lastPageContext: PageContext | null = null;
const addGlobalPageContext = (context: PageContext) => {
    if (lastPageContext) {
        removeGlobalContexts([pageContextWithSchema(lastPageContext)]);
    }
    addGlobalContexts([pageContextWithSchema(context)]);
    lastPageContext = context;
};

const addContextAndTrackPageView = (title: string, context: PageContext) => {
    addGlobalPageContext(context);
    snowplowTrackPageView({
