        const params = new URLSearchParams();
        params.set("pollId", pollId);

        const response = await fetch(`${base}/?${params}`, {
            method: "GET",
        });

        const parsed = PollApiResponse.parse(await response.json());

        if (parsed.type !== "pollGet") {
            return {
                results: null,
                status: "closed",
                pollTotalVotes: 0,
