                  .map(({ votesPercentage }) => votesPercentage ?? 0)
            : null;

        return {
            results,
            status,
            pollTotalVotes: parsed.data.options[0]?.pollTotalVotes ?? 0,
        };
    } catch (error) {
        if (error instanceof Error && !(error instanceof TypeError)) {
            captureManualException(error);
        }
        return {
            results: null,
            status: "closed",
            pollTotalVotes: 0,
        };
    }
